            {/* Filters */}
            <div className="bg-white p-4 rounded-xl shadow-sm border flex gap-4 flex-wrap items-center">
                 <div className="w-full md:w-64">
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Select Role</label>
                    <select 
                        className="w-full border p-2 rounded-lg bg-gray-50 outline-none focus:ring-2 focus:ring-galaxy-500"
                        value={impRole}
                        onChange={(e) => setImpRole(e.target.value)}
                    >
                        <option value="all">All Roles</option>
                        <option value="admin">Admin</option>
                        <option value="accountant">Accountant</option>
                        <option value="teacher">Teacher</option>
                        <option value="student">Student</option>
                        <option value="intern">Intern</option>
                    </select>
                </div>
                <div className="flex-1 min-w-[200px]">
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Search User</label>
                    <div className="relative">
                        <Search className="absolute left-3 top-2.5 text-gray-400" size={18} />
                        <input 
                            type="text" 
                            placeholder="Search by name or email..." 
                            className="w-full pl-10 pr-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-galaxy-500"
                            value={impSearch}
                            onChange={(e) => setImpSearch(e.target.value)}
                        />
                    </div>
                </div>
            </div>

            {/* User List */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {filteredUsers.length === 0 ? (
                    <div className="col-span-full text-center p-8 text-gray-500 bg-white rounded-lg border border-dashed">
