                                  <button onClick={confirmApprovalOrEdit} className="flex-1 py-2 bg-green-600 text-white rounded hover:bg-green-700 font-bold">
                                      {reviewUser.status === 'pending' ? 'Confirm & Approve' : 'Save Changes'}
